content.problemStatement:
There are n points with integer coordinates. We can form different quadrangles out of them by taking four different points and connecting them with lines. Let’s call a quadrangle ABCD nice if and only if:

Ax &gt; 0 and Ay &gt; 0;
Bx &gt; 0 and By &lt; 0;
Cx &lt; 0 and Cy &lt; 0;
Dx &lt; 0 and Dy &gt; 0;
ABCD has an integer area.

Your task is to count all different nice quadrangles that can be formed on the given points.

code.C:
#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    if (x[0] != y[0]) return x[0] - y[0];
    return x[1] - y[1];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int points[N][2];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &points[i][0], &points[i][1]);
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                for (int k = j + 1; k < N; k++) {
                    for (int l = k + 1; l < N; l++) {
                        if (points[i][0] > 0 && points[i][1] > 0 && points[j][0] > 0 && points[j][1] < 0 && points[k][0] < 0 && points[k][1] < 0 && points[l][0] < 0 && points[l][1] > 0) {
                            int area = abs(points[i][0] * points[j][1] + points[j][0] * points[k][1] + points[k][0] * points[l][1] + points[l][0] * points[i][1] - points[j][0] * points[i][1] - points[k][0] * points[j][1] - points[l][0] * points[k][1] - points[i][0] * points[l][1]);
                            if (area % 2 == 0) count++;
                        }
                    }
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

