import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[][] points = new int[N][2];
            for (int i = 0; i < N; i++) {
                points[i][0] = scanner.nextInt();
                points[i][1] = scanner.nextInt();
            }
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    for (int k = j + 1; k < N; k++) {
                        for (int l = k + 1; l < N; l++) {
                            if (points[i][0] > 0 && points[i][1] > 0 && points[j][0] > 0 && points[j][1] < 0 && points[k][0] < 0 && points[k][1] < 0 && points[l][0] < 0 && points[l][1] > 0) {
                                int area = Math.abs(points[i][0] * points[j][1] + points[j][0] * points[k][1] + points[k][0] * points[l][1] + points[l][0] * points[i][1] - points[j][0] * points[i][1] - points[k][0] * points[j][1] - points[l][0] * points[k][1] - points[i][0] * points[l][1]);
                                if (area % 2 == 0) count++;
                            }
                        }
                    }
                }
            }
            System.out.println(count);
        }
    }
}

